"use client";

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Block } from '@/lib/types';

export interface JournalEntry {
  id: string;
  title: string;
  blocks: Block[];
  createdAt: string;
  updatedAt: string;
}

interface JournalContextValue {
  entries: JournalEntry[];
  selectedEntry: JournalEntry | null;
  createEntry: (title: string) => void;
  updateEntry: (id: string, blocks: Block[]) => void;
  deleteEntry: (id: string) => void;
  selectEntry: (id: string) => void;
  reorderEntries: (fromIndex: number, toIndex: number) => void;
}

const JournalContext = createContext<JournalContextValue | undefined>(undefined);

export function JournalProvider({ children }: { children: React.ReactNode }) {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [selectedEntryId, setSelectedEntryId] = useState<string | null>(null);

  // Load entries from localStorage
  useEffect(() => {
    try {
      const stored = localStorage.getItem('journalEntries');
      if (stored) {
        setEntries(JSON.parse(stored));
      }
    } catch {
      // ignore
    }
  }, []);

  // Persist entries to localStorage
  useEffect(() => {
    localStorage.setItem('journalEntries', JSON.stringify(entries));
  }, [entries]);

  const selectedEntry = entries.find((e) => e.id === selectedEntryId) || null;

  const createEntry = useCallback((title: string) => {
    const now = new Date().toISOString();
    const newEntry: JournalEntry = {
      id: Date.now().toString(),
      title,
      blocks: [],
      createdAt: now,
      updatedAt: now,
    };
    setEntries((prev) => [newEntry, ...prev]);
    setSelectedEntryId(newEntry.id);
  }, []);

  const updateEntry = useCallback((id: string, blocks: Block[]) => {
    setEntries((prev) =>
      prev.map((e) =>
        e.id === id ? { ...e, blocks, updatedAt: new Date().toISOString() } : e
      )
    );
  }, []);

  const deleteEntry = useCallback((id: string) => {
    setEntries((prev) => prev.filter((e) => e.id !== id));
    if (selectedEntryId === id) {
      setSelectedEntryId(null);
    }
  }, [selectedEntryId]);

  const selectEntry = useCallback((id: string) => {
    setSelectedEntryId(id);
  }, []);

  const reorderEntries = useCallback((fromIndex: number, toIndex: number) => {
    setEntries((prev) => {
      const items = Array.from(prev);
      const [moved] = items.splice(fromIndex, 1);
      items.splice(toIndex, 0, moved);
      return items;
    });
  }, []);

  return (
    <JournalContext.Provider
      value={{ entries, selectedEntry, createEntry, updateEntry, deleteEntry, selectEntry, reorderEntries }}
    >
      {children}
    </JournalContext.Provider>
  );
}

export function useJournal() {
  const ctx = useContext(JournalContext);
  if (!ctx) {
    throw new Error('useJournal must be used within JournalProvider');
  }
  return ctx;
} 